{
var seed = GetInt(parameters, "seed", context.Seed);
    var scale = GetFloat(parameters, "scale", 1f);
    var octaves = Math.Max(1, GetInt(parameters, "octaves", 6));
    var persistence = GetFloat(parameters, "persistence", 0.5f);
    var lacunarity = GetFloat(parameters, "lacunarity", 2f);
    var erosion = GetFloat(parameters, "erosion", 0.3f);
    var steepness = GetFloat(parameters, "steepness", 0.5f);
    var colorCount = Math.Clamp(GetInt(parameters, "colorCount", 5), 3, 8);
    var seaLevel = GetFloat(parameters, "seaLevel", 0.35f);
    var snowLine = GetFloat(parameters, "snowLine", 0.75f);
    var invert = GetBool(parameters, "invert", false);

    // Read up to 6 colors
    var colors = new[]
    {
        GetColor(parameters, "color1(DeepSea)", Color.FromRgb(20, 40, 120)),
        GetColor(parameters, "color2(ShallowSea)", Color.FromRgb(60, 120, 200)),
        GetColor(parameters, "color3(Sand)", Color.FromRgb(220, 200, 150)),
        GetColor(parameters, "color4(Grass)", Color.FromRgb(80, 160, 60)),
        GetColor(parameters, "color5(Rock)", Color.FromRgb(140, 130, 120)),
        GetColor(parameters, "color6(Snow)", Color.FromRgb(240, 245, 250))
    };

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);

    var hasInput = inputs.Length > 0 && inputs[0] != null;

    // Seamless coordinate mapping: noise coordinates are set up so that
    // pixel (0, y) and pixel (size-1, y) map to equivalent positions in
    // the periodic noise function, producing tileable output.
    var edge = Math.Max(1, size - 1);
    var noiseCells = Math.Max(2, (int)(scale * 4 + 0.5f));

    buffer.ParallelForEachPixel((x, y) =>
    {
        float height;

        if (hasInput)
        {
            // Use input mask as heightmap
            var (_, _, _, heightVal) = inputs[0]!.GetPixel(x, y);
            height = heightVal;
        }
        else
        {
            // Map x,y in [0, size-1] to noise coords in [0, noiseCells]
            // ensuring tileable wrapping at edges.
            var nu = (float)x / edge * noiseCells;
            var nv = (float)y / edge * noiseCells;

            // Ridged multifractal noise
            height = RidgedMultifractal(nu, nv, noiseCells, octaves, persistence, lacunarity, steepness, seed);

            // Simple erosion simulation: blur high-slope areas
            if (erosion > 0f)
            {
                var localSlope = ComputeLocalSlope(nu, nv, noiseCells, seed);
                var erosionFactor = localSlope * erosion * 0.3f;
                height = height - erosionFactor;
            }

            height = Math.Clamp(height, 0f, 1f);
        }

        if (invert) height = 1f - height;

        // Color mapping using seaLevel and snowLine
        float r, g, b;

        // Remap height so seaLevel/snowLine control the color band boundaries:
        //   [0, seaLevel]      → water bands (first 1/3 of color range)
        //   [seaLevel, snowLine] → land bands (middle 1/3)
        //   [snowLine, 1]       → snow band (last 1/3)
        float remapped;
        if (height <= seaLevel)
            remapped = seaLevel > 0.001f ? height / seaLevel * 0.33f : 0f;
        else if (height >= snowLine)
            remapped = 0.66f + (snowLine < 0.999f ? (height - snowLine) / (1f - snowLine) * 0.34f : 0f);
        else
            remapped = 0.33f + (height - seaLevel) / (snowLine - seaLevel) * 0.33f;

        remapped = Math.Clamp(remapped, 0f, 1f);

        var bandPos = remapped * (colorCount - 1);
        var bandIndex = (int)MathF.Floor(bandPos);
        var bandT = bandPos - bandIndex;
        bandIndex = Math.Clamp(bandIndex, 0, colorCount - 2);

        var c0 = colors[bandIndex];
        var c1 = colors[Math.Min(bandIndex + 1, colors.Length - 1)];

        r = Lerp(c0.R / 255f, c1.R / 255f, bandT);
        g = Lerp(c0.G / 255f, c1.G / 255f, bandT);
        b = Lerp(c0.B / 255f, c1.B / 255f, bandT);

        // Add fine terrain detail noise (not color-mapped, also seamless)
        if (!hasInput)
        {
            var detailCells = Math.Max(2, edge / 4);
            var detail = TileableFractalNoise(
                (float)x / edge * detailCells,
                (float)y / edge * detailCells,
                detailCells, 2, 0.5f, 2f, seed + 999);
            var detailAmt = (detail - 0.5f) * 0.06f;
            r = Math.Clamp(r + detailAmt, 0f, 1f);
            g = Math.Clamp(g + detailAmt * 0.9f, 0f, 1f);
            b = Math.Clamp(b + detailAmt * 0.8f, 0f, 1f);
        }

        buffer.SetPixel(x, y, r, g, b, 1f);
    });

    return buffer;

private static float RidgedMultifractal(float x, float y, int period, int octaves,
    float persistence, float lacunarity, float steepness, int seed)
{
    var value = 0f;
    var amplitude = 1f;
    var frequency = 1f;
    var maxVal = 0f;
    var offset = 1f;

    for (var o = 0; o < octaves; o++)
    {
        var octavePeriod = Math.Max(1, (int)(period * frequency));
        var noise = TileableValueNoise(x * frequency, y * frequency, octavePeriod, seed + o * 1013);

        // Ridge: 1 - |noise|, creates sharp valleys
        var ridge = 1f - MathF.Abs(noise * 2f - 1f);
        ridge = MathF.Pow(ridge, 1f + steepness);
        ridge *= ridge; // Sharper ridges

        value += ridge * amplitude * offset;
        maxVal += amplitude;
        amplitude *= persistence;
        frequency *= lacunarity;
        offset *= 0.9f; // Reduce offset per octave
    }

    return maxVal > 0f ? value / maxVal : 0f;
}

private static float ComputeLocalSlope(float x, float y, int period, int seed)
{
    var eps = 0.05f;
    var h0 = TileableValueNoise(x - eps, y, period, seed);
    var h1 = TileableValueNoise(x + eps, y, period, seed);
    var h2 = TileableValueNoise(x, y - eps, period, seed);
    var h3 = TileableValueNoise(x, y + eps, period, seed);

    var dx = (h1 - h0) / (2f * eps);
    var dy = (h3 - h2) / (2f * eps);
    return MathF.Sqrt(dx * dx + dy * dy);
    }
}
